@app.post("/webhooks/telegram")
async def telegram_webhook(request: Request):
    """Telegram Bot API webhook — returns 200 OK in <100ms regardless of
    payload type. Heavy work runs in a separate OS thread."""
    expected_secret = settings.telegram_webhook_secret
    if not expected_secret:
        log.error("TELEGRAM_WEBHOOK_SECRET not set — refusing all updates (fail-closed).")
        return Response(status_code=503)
    got_secret = request.headers.get("x-telegram-bot-api-secret-token", "")
    if not hmac.compare_digest(expected_secret.encode("utf-8"), got_secret.encode("utf-8")):
        log.warning("telegram_webhook: secret-token mismatch — rejected forged update")
        return Response(status_code=401)

    payload = await request.json()
    update_id = payload.get("update_id")
    if _seen_update(update_id):
        return {"ok": True, "dedup": True}

    threading.Thread(
        target=_process_in_thread,
        args=(payload,),
        daemon=True,
        name=f"tg-update-{update_id}",
    ).start()
    return {"ok": True}

def parse_followup_when(text: Optional[str], now: Optional[datetime] = None) -> Optional[datetime]:
    """Вернуть aware-UTC datetime, когда лид просит написать, либо None.
    Поддержка: «через N минут/часов/дней/недель», «завтра», «послезавтра»,
    «в <день недели>», «на следующей неделе»."""
    if not text:
        return None
    now = now or datetime.now(timezone.utc)
    if now.tzinfo is None:
        now = now.replace(tzinfo=timezone.utc)
    t = text.lower().replace("ё", "е")

    m = re.search(r"через\s+(\d+)\s*(минут|мин|час|часа|часов|день|дня|дней|недел)", t)
    if m:
        n = int(m.group(1)); unit = m.group(2)
        if unit.startswith("мин"):
            return now + timedelta(minutes=n)
        if unit.startswith("час"):
            return now + timedelta(hours=n)
